  "dbc.sagasdb.1.1": "Hello! Thank you for finding my turtle!",
  "dbc.sagasdb.1.d": "Here, use this present as you please",
  "dbc.sagasdb.2.1": "Yamcha: Heh, you are just a kid.",
  "dbc.sagasdb.2.d": "Yamcha: W-what?",
  "dbc.sagasdb.3.1": "Pilaf: Don't stand in our way!",
  "dbc.sagasdb.3.d": "Pilaf: Alright everyone, gear up!",
  "dbc.sagasdb.3.2": "Shu: We'll show you!",
  "dbc.sagasdb.3.d2": "",
  "dbc.sagasdb.3.3": "Mai: Let's show him!",
  "dbc.sagasdb.3.d3": "",
  "dbc.sagasdb.4.1": "",
  "dbc.sagasdb.4.d": "Pilaf: B-b-but I am Pilaf!",
  "dbc.sagasdb.4.2": "",
  "dbc.sagasdb.4.d2": "Shu: Aah",
  "dbc.sagasdb.4.3": "",
  "dbc.sagasdb.4.d3": "Mai: Iiih",
  "dbc.sagasdb.5.1": "Pilaf: Now with this, you can't hurt us anymore!",
  "dbc.sagasdb.5.d": "Pilaf: Whaaat?",
  "dbc.sagasdb.7.1": "Bacterian: Here we go heheheh",
  "dbc.sagasdb.7.d": "Bacterian: UEEeeh",
  "dbc.sagasdb.8.1": "Yamcha: I'll show you just how strong I've become",
  "dbc.sagasdb.8.d": "Yamcha: I guess I have still a lot to learn",
  "dbc.sagasdb.9.1": "Jackie-chun: I'll show you what a true martial artist can do",
  "dbc.sagasdb.9.d": "",
  "dbc.sagasdb.10.1": "Jackie-chun: This is my full power!",
  "dbc.sagasdb.10.d": "Jackie-chun: Heheh, not bad",
  "dbc.sagasdb.12.1": "Colonel Silver: So you are looking for the Dragon balls as well heh?",
  "dbc.sagasdb.12.d": "Colonel Silver: Ooooh",
  "dbc.sagasdb.13.1": "Major Metallitron: Stop intruder!",
  "dbc.sagasdb.13.d": "Major Metallitron: Bzzzt",
  "dbc.sagasdb.14.1": "Ninja Murasaki: Enough talk!",
  "dbc.sagasdb.14.d": "Ninja Murasaki: Haaai Haii Haiii",
  "dbc.sagasdb.15.1": "Android 8: I-I don't want to hurt you...",
  "dbc.sagasdb.15.d": "Android 8: Thank you",
  "dbc.sagasdb.16.1": "Buyon: Heheheh",
  "dbc.sagasdb.16.d": "Buyon: Iiiiih",
  "dbc.sagasdb.17.1": "General white: Hah, I guess I have no choice but to surrender...",
  "dbc.sagasdb.17.d": "General white: But how?",
  "dbc.sagasdb.18.1": "General blue: You little runt",
  "dbc.sagasdb.18.d": "General blue: Aaa aah",
  "dbc.sagasdb.19.1": "Mercenary Tao: Do you have any last words?",
  "dbc.sagasdb.19.d": "Mercenary Tao: WAaaaaaah",
  "dbc.sagasdb.21.1": "Staff Officer Black: I will take you to pieces",
  "dbc.sagasdb.21.d": "Staff Officer Black: WHAT!? NOOO",
  "dbc.sagasdb.23.1": "Fangs the Vampire: HAAH HAHAHAH",
  "dbc.sagasdb.23.d": "Fangs the Vampire: AAaaah",
  "dbc.sagasdb.24.1": "Invisible Man: Heheh",
  "dbc.sagasdb.24.d": "Invisible Man: W-what?",
  "dbc.sagasdb.25.1": "Bandages the Mummy: AAhhahaHahah",
  "dbc.sagasdb.25.d": "Bandages the Mummy: Huaaaah",
  "dbc.sagasdb.26.1": "Spike the Devil: Beware!",
  "dbc.sagasdb.26.d": "Spike the Devil: Bwwww",
  "dbc.sagasdb.27.1": "Masked man: Ready?",
  "dbc.sagasdb.27.d": "Masked man: I surrender, I am defeated",
  "dbc.sagasdb.29.1": "Yamcha: Alright, let's go!",
  "dbc.sagasdb.29.d": "Yamcha: Not bad as always",
  "dbc.sagasdb.30.1": "Chiaotzu: ...",
  "dbc.sagasdb.30.d": "Chiaotzu: BUEEeeh",
  "dbc.sagasdb.31.1": "Krillin: Are you ready?",
  "dbc.sagasdb.31.d": "Krillin: I couldn't barely keep up",
  "dbc.sagasdb.32.1": "Tien Shinhan: Hmmm",
  "dbc.sagasdb.32.d": "Tien Shinhan: AAah uff",
  "dbc.sagasdb.34.1": "Tambourine: Did I make you cry?",
  "dbc.sagasdb.34.d": "Tambourine: HAHAHAHahah",
  "dbc.sagasdb.35.1": "Cymbal: If you are so eager to die who am I to stand in your way...",
  "dbc.sagasdb.35.d": "Cymbal: Hee? AAAaaaaah",
  "dbc.sagasdb.36.1": "Tambourine: I'm waiting",
  "dbc.sagasdb.36.d": "Tambourine: HUAAAAh",
  "dbc.sagasdb.37.1": "King Piccolo: You are quick",
  "dbc.sagasdb.37.d": "King Piccolo: HAHAHAHAHAH",
  "dbc.sagasdb.39.1": "Drum: Heheheh. You're not going anywhere",
  "dbc.sagasdb.39.d": "Drum: WAAAaaaah",
  "dbc.sagasdb.40.1": "King Piccolo: This will have to be a quick demonstration, I apologize",
  "dbc.sagasdb.40.d": "King Piccolo: HAAh... Good luck... my son, get revenge, destroy all of my enemies",
  "dbc.sagasdb.41.1": "Kami: Hello! Are you here to train?",
  "dbc.sagasdb.41.d": "Kami: Alright, let's see what I can teach you...",
  "dbc.sagasdb.43.1": "Mercenary Tao: Heheheh",
  "dbc.sagasdb.43.d": "Mercenary Tao: AAAAAAAA AAAA AAA",
  "dbc.sagasdb.44.1": "Tien Shinhan: HEheh",
  "dbc.sagasdb.44.d": "Tien Shinhan: I won't pretent I'm not wounded, but it's only my pride",
  "dbc.sagasdb.45.1": "Piccolo Jr.: HAAAaaaa",
  "dbc.sagasdb.45.d": "",
  "dbc.sagasdb.46.1": "Piccolo Jr.: HAHAHA. Do you really believe that you can defeat me?",
  "dbc.sagasdb.46.d": "Piccolo Jr.: GUUUH AAAaaaah ",
  "dbc.sagadbsbroly.1.1": "Vegeta: You might not want to face the prince of all Saiyans",
  "dbc.sagadbsbroly.1.d": "Vegeta: Let's see if you can handle me at my full power",
  "dbc.sagadbsbroly.2.1": "Goku: No way, it is my turn now!",
  "dbc.sagadbsbroly.2.d": "Goku: Heheh, you are pretty strong.",
  "dbc.sagadbsbroly.3.1": "Paragus: Now go, Broly!",
  "dbc.sagadbsbroly.3.d": "Vegeta: He is learning as he fights...",
  "dbc.sagadbsbroly.4.1": "Broly: HAAAA!",
  "dbc.sagadbsbroly.4.d": "Goku: Oh wow, he is just in his base form and he is this powerful?!",
  "dbc.sagadbsbroly.5.1": "Broly: GRAAAAAAH!",
  "dbc.sagadbsbroly.5.d": "Frieza: His power is magnificent!",
  "dbc.sagadbsbroly.6.1": "Broly: HUAAAAAAH!",
  "dbc.sagadbsbroly.6.d": "Broly: Eeeh?",
